5	func TestInferExternalRepoURL_TypeScript(t *testing.T) {
6		tests := []struct {
7			modPath string
8			want    string
9		}{
10			// External packages.
11			{"react", "external://react"},
12			{"@nestjs/common", "external://@nestjs/common"},
13			{"lodash/debounce", "external://lodash"},
14			{"@scope/pkg/sub", "external://@scope/pkg"},
15			{"express", "external://express"},
16			{"@types/node", "external://@types/node"},
17			{"vue/dist/vue.esm", "external://vue"},
18	
19			// Relative imports (not external).
20			{"./local", ""},
21			{"../relative", ""},
22			{"./components/Button", ""},
23			{"../utils/format", ""},
24			{"/absolute/path", ""},
25		}
26	
27		for _, tt := range tests {
28			got := InferExternalRepoURL(tt.modPath, "", TypeScriptConfig)
29			if got != tt.want {
30				t.Errorf("InferExternalRepoURL(%q, TypeScript) = %q, want %q", tt.modPath, got, tt.want)
31			}
32		}
33	}
34	
35	func TestInferExternalRepoURL_Python(t *testing.T) {
36		tests := []struct {
37			moduleName string
38			want       string
39		}{
40			{"flask", "external://flask"},
41			{"os", "stdlib"},
42			{"numpy.linalg", "external://numpy"},
43			{".local_module", ""},
44			{"sys", "stdlib"},
45			{"requests", "external://requests"},
46			{"..parent_module", ""},
47			{"django.db.models", "external://django"},
48			{"pathlib", "stdlib"},
49			{"json", "stdlib"},
50			{"typing", "stdlib"},
51			{"pandas", "external://pandas"},
52		}
53	
54		for _, tt := range tests {
55			got := InferExternalRepoURL(tt.moduleName, "", PythonConfig)
56			if got != tt.want {
57				t.Errorf("InferExternalRepoURL(%q, Python) = %q, want %q", tt.moduleName, got, tt.want)
58			}
59		}
60	}
61	
62	func TestInferExternalRepoURL_Rust(t *testing.T) {
63		tests := []struct {
64			usePath string
65			want    string
66		}{
