	// Positive cases: known stdlib modules.
	stdlibNames := []string{
		"os", "sys", "re", "io", "json", "math", "time", "datetime",
		"collections", "itertools", "functools", "pathlib", "typing",
		"abc", "ast", "asyncio", "logging", "subprocess", "threading",
