	if cfg.StdlibCheck != nil && cfg.StdlibCheck(topLevel) {
		return "stdlib"
	}

	// External: extract package name.
	if cfg.ExtractPkgName != nil {
		return "external://" + cfg.ExtractPkgName(path)
	}

	return "external://" + topLevel
}

