		usePath string
		want    string
	}{
		{"tokio::runtime", "external://tokio"},
		{"crate::config", ""},
		{"std::collections", "stdlib"},
		{"serde::Deserialize", "external://serde"},
		{"core::fmt", "stdlib"},
		{"alloc::vec", "stdlib"},
		{"super::helpers", ""},
		{"self::module", ""},
		{"hyper::client::Client", "external://hyper"},
		{"", ""},
	}

	for _, tt := range tests {
		got := InferExternalRepoURL(tt.usePath, "", RustConfig)
